// Extract Evolution API webhook payload
const evolutionPayload = $json.body || $json;

// Parse Evolution message structure
const message = evolutionPayload.data?.message || evolutionPayload.message || {};
const phoneE164 = evolutionPayload.data?.from || evolutionPayload.from;
const messageId = message.id || message.key?.id || `${phoneE164}-${Date.now()}`;
const direction = message.fromMe !== undefined ? (message.fromMe ? 'outbound' : 'inbound') : 'inbound';
const content = message.body || message.text || '';
const eventTs = new Date(message.timestamp * 1000).toISOString();

// Normalize to unified contract
return {
  channel: 'whatsapp',
  session_id: `${phoneE164}-whatsapp-session`, // Session per phone number on WhatsApp
  phone_e164: phoneE164,
  email: null, // WhatsApp doesn't provide email
  contact_id: null, // To be resolved by orchestrator
  message_id: messageId,
  direction: direction,
  event_ts: eventTs,
  source_label: 'whatsapp',
  content: content,
  raw_evolution_payload: evolutionPayload,
  _metadata: {
    evolution_message_key: message.key,
    evolution_from_me: message.fromMe,
    evolution_status: message.status
  }
};

// Anti-loop guard: skip if outbound (our own message echoed back)
const normalized = $json;

if (normalized.direction === 'outbound') {
  return { skip: true, reason: 'outbound_echo_skipped' };
}

return { skip: false, event: normalized };
